const PROCESSING_FEE = 5;

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: "quote"; items: Array<{ type: string }> }>;
};

type QuoteResult = { premium: number };

const quotePremium = (items: Array<{ type: string }>): number => {
  if (items.length === 0) return PROCESSING_FEE;
  return 110 + PROCESSING_FEE;
};

export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

